mapper.select:
SELECT c.id, c.name, c.room, c.begin_date AS beginDate, c.end_date AS endDate, c.master_id AS masterId, c.subject AS subject, c.create_time AS createTime, c.update_time AS updateTime, IFNULL(e.name, '未分配') AS masterName, CASE WHEN NOW() <= c.begin_date THEN '未开班' WHEN NOW() > c.end_date THEN '已结课' ELSE '已开班' END AS status FROM clazz AS c LEFT JOIN emp AS e ON c.master_id = e.id
c.subject = #{subject}
AND c.name LIKE CONCAT('%', #{name}, '%')
AND c.begin_date >= #{begin}
AND c.end_date <= #{end}
